1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: Item[];
15	}
16	
17	const RUNE_TYPE = "rune";
18	const PROCESSING_FEE = 5;
19	const BLOCK_SIZE = 3;
20	const RUNE_BLOCK_PREMIUM = 60;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const LOYALTY_RATE = 0.2;
23	const LOYALTY_MIN_YEARS = 2;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	};
35	
36	const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
37	
38	const isRune = (item: Item): boolean => item.type === RUNE_TYPE;
39	
40	const isMainItem = (item: Item): boolean => !isRune(item);
41	
42	const runeBasePremium = (runeCount: number): number =>
43	  runeCount === BLOCK_SIZE
44	    ? RUNE_BLOCK_PREMIUM
45	    : runeCount * unitPriceFor(RUNE_TYPE);
46	
47	const sumUnitPrices = (items: Item[]): number =>
48	  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);
49	
50	const countRunes = (items: Item[]): number => items.filter(isRune).length;
51	
52	const totalBasePremium = (items: Item[]): number =>
53	  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));
54	
55	const isHighlyEnchanted = (item: Item): boolean =>
56	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
57	
58	const itemSurchargeRate = (item: Item): number =>
59	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
60	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
61	
62	const itemSurcharges = (item: Item): number =>
63	  unitPriceFor(item.type) * itemSurchargeRate(item);
64	
65	const totalSurcharges = (items: Item[]): number =>
66	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
67	
68	const firstInsuranceSurcharge = (policyBase: number): number =>
69	  policyBase * FIRST_INSURANCE_RATE;
70	
71	const isLoyal = (customer: Customer): boolean =>
72	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
73	
74	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
75	  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;
76	
77	export const quote = (input: QuoteInput): number => {
78	  const policyBase = totalBasePremium(input.items);
79	  const premiumBeforeFee =
80	    policyBase +
81	    totalSurcharges(input.items) +
82	    firstInsuranceSurcharge(policyBase) -
83	    loyaltyDiscount(policyBase, input.customer);
84	  return Math.ceil(premiumBeforeFee + PROCESSING_FEE);
85	};
86	
87	export const claim = (...args: unknown[]): unknown => {
88	  return undefined;
89	};
