132	  it.todo("claim: dragon-material sword, ench 5, damage 800 → payout 700 G (dragon full reimbursement, then deductible)");
133	  it.todo("claim: steel sword, ench 9, damage 1000 → payout 400 G (high-enchantment 50% first, then deductible)");
