145	  it.todo("claim: sword (cap 2000), first claim 1500 → payout 1400, remaining cap 600");
146	  it.todo("claim: sword (cap 2000), second claim 1500 → payout 600 (reduced to remaining cap), remaining cap 0");
147	
148	  // --- Claim: rounding ---
149	  it.todo("claim: payout of 350.5 G rounds DOWN to 350 G (MHPCO's favor)");
150	
151	  // --- Error / edge cases ---
